const sbUrl = $('Secrets').item.json.supabase_url;
const sbKey  = $('Secrets').item.json.supabase_key;
const appSecret = 'CONFIGURE_APP_SECRET';
const sbHeaders = { apikey: sbKey, Authorization: 'Bearer ' + sbKey };

const now = new Date().toISOString();

let due;
try {
  due = await helpers.httpRequest({
    method: 'GET',
    url: sbUrl + '/rest/v1/bot_reminders?fire_at=lte.' + now + '&sent=eq.false&select=*&limit=50',
    headers: sbHeaders
  });
} catch(e) {
  console.error('fetch reminders failed:', e.message);
  return [{ json: { processed: 0, error: e.message } }];
}

const reminders = Array.isArray(due) ? due : [];
if (!reminders.length) return [{ json: { processed: 0 } }];

const vercelBase = 'https://whatsapp-hrbot.vercel.app';
const authHeader = { Authorization: 'Bearer ' + appSecret, 'Content-Type': 'application/json' };
const results = [];

for (const r of reminders) {
  try {
    if (r.type === 'task') {
      await helpers.httpRequest({
        method: 'POST',
        url: vercelBase + '/api/reminders/task',
        headers: authHeader,
        body: JSON.stringify({
          task_id:            r.task_id,
          reminder:           r.task_reminder,
          scheduled_deadline: r.scheduled_deadline,
          scheduled_due_time: r.scheduled_due_time,
        })
      });
    } else {
      await helpers.httpRequest({
        method: 'POST',
        url: vercelBase + '/api/reminders/custom',
        headers: authHeader,
        body: JSON.stringify({
          wa_number:       r.wa_number,
          message:         r.custom_message,
          organization_id: r.organization_id,
          user_id:         r.user_id,
        })
      });
    }
    await helpers.httpRequest({
      method: 'PATCH',
      url: sbUrl + '/rest/v1/bot_reminders?id=eq.' + r.id,
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify({ sent: true, sent_at: new Date().toISOString() })
    });
    results.push({ id: r.id, type: r.type, status: 'sent' });
  } catch(e) {
    results.push({ id: r.id, type: r.type, status: 'error', error: e.message });
  }
}

return [{ json: { processed: results.length, results } }];

